import pygame
import random
from collections import defaultdict
from task0 import GRID_WIDTH, GRID_HEIGHT, GEM_COLORS, MATCH_CLEAR_SCORES, CHAIN_BONUS_MULTIPLIER

def detect_matches(grid):
    """Detects horizontal and vertical matches of 3 or more gems in the grid."""
    matches = []

    # Horizontal matches
    for row in range(GRID_HEIGHT):
        for col in range(GRID_WIDTH - 2):
            if grid[row][col] and grid[row][col] == grid[row][col+1] == grid[row][col+2]:
                match_len = 3
                while col + match_len < GRID_WIDTH and grid[row][col] == grid[row][col + match_len]:
                    match_len += 1
                matches.append([(row, c) for c in range(col, col + match_len)])

    # Vertical matches
    for col in range(GRID_WIDTH):
        for row in range(GRID_HEIGHT - 2):
            if grid[row][col] and grid[row][col] == grid[row+1][col] == grid[row+2][col]:
                match_len = 3
                while row + match_len < GRID_HEIGHT and grid[row][col] == grid[row + match_len][col]:
                    match_len += 1
                matches.append([(r, col) for r in range(row, row + match_len)])

    # Merge overlapping matches
    merged_matches = []
    for match in matches:
        is_merged = False
        for existing_match in merged_matches:
            if any(cell in existing_match for cell in match):
                existing_match.extend([cell for cell in match if cell not in existing_match])
                is_merged = True
                break
        if not is_merged:
            merged_matches.append(match)

    # Remove duplicate cells within each match and convert to set of tuples
    merged_matches = [list(dict.fromkeys(match)) for match in merged_matches]  # Remove duplicates while preserving order

    return merged_matches


def clear_matches(grid, matches):
    """Clears the matched gems from the grid."""
    cleared_count = 0
    for match in matches:
        for row, col in match:
            if grid[row][col] is not None:
                grid[row][col] = None
                cleared_count += 1
    return cleared_count


def apply_gravity(grid):
    """Applies gravity to the grid, moving gems down to fill empty spaces."""
    for col in range(GRID_WIDTH):
        empty_row = -1
        for row in range(GRID_HEIGHT - 1, -1, -1):
            if grid[row][col] is None and empty_row == -1:
                empty_row = row
            elif grid[row][col] is not None and empty_row != -1:
                grid[empty_row][col] = grid[row][col]
                grid[row][col] = None
                empty_row -= 1
    return grid


def resolve_matches(grid):
    """Resolves gem matches, applies gravity, and handles chain reactions."""
    total_score = 0
    chain_multiplier = 1.0
    total_cleared = 0

    while True:
        matches = detect_matches(grid)
        if not matches:
            break

        cleared_count = clear_matches(grid, matches)
        total_cleared += cleared_count

        # Calculate score for this match
        match_size = max(len(match) for match in matches) if matches else 0
        if match_size in MATCH_CLEAR_SCORES:
            score = int(MATCH_CLEAR_SCORES[match_size] * chain_multiplier)
            total_score += score
            chain_multiplier *= CHAIN_BONUS_MULTIPLIER

        grid = apply_gravity(grid)

    return grid, total_score, total_cleared
